import{_ as o,o as a,c as t,a2 as r}from"./chunks/framework.0AV_2kjq.js";const y=JSON.parse('{"title":"Privacy Policy","description":"","frontmatter":{"head":[["link",{"rel":"canonical","href":"https://moviplayer.com/docs/privacy-policy"}]]},"headers":[],"relativePath":"privacy-policy.md","filePath":"privacy-policy.md"}'),i={name:"privacy-policy.md"};function s(n,e,l,c,d,h){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="privacy-policy" tabindex="-1">Privacy Policy <a class="header-anchor" href="#privacy-policy" aria-label="Permalink to &quot;Privacy Policy&quot;">​</a></h1><p><strong>Last updated:</strong> April 9, 2026</p><p><strong>Movi Player — Chrome Extension &amp; Web Player</strong></p><p>Movi Player is an open-source video player. Your privacy matters to us, and we have designed Movi Player to work entirely on your device.</p><h2 id="data-collection" tabindex="-1">Data Collection <a class="header-anchor" href="#data-collection" aria-label="Permalink to &quot;Data Collection&quot;">​</a></h2><p>Movi Player does <strong>not</strong> collect, store, transmit, or share any personal data or user information. Specifically:</p><ul><li><strong>No analytics or tracking</strong> — We do not use any analytics services, tracking pixels, or telemetry.</li><li><strong>No user accounts</strong> — Movi Player does not require sign-up or authentication.</li><li><strong>No cookies</strong> — We do not set or read any cookies.</li><li><strong>No network requests to our servers</strong> — Movi Player does not communicate with any server operated by us. All video decoding and playback happens locally on your device.</li></ul><h2 id="video-playback" tabindex="-1">Video Playback <a class="header-anchor" href="#video-playback" aria-label="Permalink to &quot;Video Playback&quot;">​</a></h2><p>When you play a video from a URL, Movi Player fetches the video data directly from the source URL you provide. This network request goes directly from your browser to the video host — Movi Player does not proxy, intercept, or log these requests.</p><p>When you play a local file, the file is read entirely on your device and never uploaded anywhere.</p><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><p>The Chrome extension requests the following permissions:</p><table tabindex="0"><thead><tr><th>Permission</th><th>Purpose</th></tr></thead><tbody><tr><td><code>contextMenus</code></td><td>To add a &quot;Play with Movi Player&quot; option when you right-click a video link</td></tr><tr><td><code>activeTab</code></td><td>To detect video URLs on the current page</td></tr><tr><td><code>clipboardRead</code></td><td>To allow pasting video URLs directly into the player</td></tr></tbody></table><p>These permissions are used solely for their stated purpose and do not grant access to browsing history, personal data, or any other information.</p><h2 id="local-storage" tabindex="-1">Local Storage <a class="header-anchor" href="#local-storage" aria-label="Permalink to &quot;Local Storage&quot;">​</a></h2><p>Movi Player may store your playback preferences (such as volume level and resume position) in your browser&#39;s local storage. This data stays on your device and is never transmitted externally.</p><h2 id="third-party-services" tabindex="-1">Third-Party Services <a class="header-anchor" href="#third-party-services" aria-label="Permalink to &quot;Third-Party Services&quot;">​</a></h2><p>Movi Player does not integrate with or send data to any third-party services.</p><h2 id="open-source" tabindex="-1">Open Source <a class="header-anchor" href="#open-source" aria-label="Permalink to &quot;Open Source&quot;">​</a></h2><p>Movi Player is open source. You can review the entire source code at <a href="https://github.com/MrUjjwalG/movi-player" target="_blank" rel="noreferrer">github.com/MrUjjwalG/movi-player</a>.</p><h2 id="changes-to-this-policy" tabindex="-1">Changes to This Policy <a class="header-anchor" href="#changes-to-this-policy" aria-label="Permalink to &quot;Changes to This Policy&quot;">​</a></h2><p>If we make changes to this privacy policy, we will update the &quot;Last updated&quot; date above.</p><h2 id="contact" tabindex="-1">Contact <a class="header-anchor" href="#contact" aria-label="Permalink to &quot;Contact&quot;">​</a></h2><p>If you have questions about this privacy policy, please open an issue on our <a href="https://github.com/MrUjjwalG/movi-player/issues" target="_blank" rel="noreferrer">GitHub repository</a>.</p>',24)])])}const u=o(i,[["render",s]]);export{y as __pageData,u as default};
